export function carrierScriptSurfaceFor(relativePath) {
  const normalized = String(relativePath).replaceAll('\\', '/');
  const canonical = CARRIER_SCRIPT_OWNERSHIP[normalized];
  if (!canonical) throw new Error(`cloudflare_carrier_script_unowned:${normalized}`);
  const surface = canonical.split('/')[1];
  if (!CARRIER_SCRIPT_SURFACES[surface === 'read-models' ? 'read_models' : surface]) {
    throw new Error(`cloudflare_carrier_script_surface_unknown:${normalized}`);
  }
  return surface === 'read-models' ? 'read_models' : surface;
}

export function canonicalSurfacePath(surfaceId, fileName) {
  const surface = CARRIER_SCRIPT_SURFACES[surfaceId];
  if (!surface) throw new Error(`cloudflare_carrier_script_surface_unknown:${surfaceId}`);
  const path = `${surface.directory}/${fileName}`;
  if (!CARRIER_SCRIPT_OWNERSHIP[path]) throw new Error(`cloudflare_carrier_script_unowned:${path}`);
  return path;
}
